@_documentation(visibility: private)
#endif
fileprivate struct FfiConverterSequenceTypeCvCertificate: FfiConverterRustBuffer {
    typealias SwiftType = [CvCertificate]

    public static func write(_ value: [CvCertificate], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterTypeCvCertificate.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [CvCertificate] {
        let len: Int32 = try readInt(&buf)
        var seq = [CvCertificate]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeCvCertificate.read(from: &buf))
        }
        return seq
    }
}

