private enum InitializationResult {
    case ok
    case contractVersionMismatch
    case apiChecksumMismatch
}
// Use a global variable to perform the versioning checks. Swift ensures that
// the code inside is only computed once.
private let initializationResult: InitializationResult = {
    // Get the bindings contract version from our ComponentInterface
    let bindings_contract_version = 30
    // Get the scaffolding contract version by calling the into the dylib
    let scaffolding_contract_version = ffi_openhealth_crypto_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_aes_cmac() != 57035) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_brainpool_p256r1_ecdh() != 17156) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_generate_brainpool_p256r1_key_pair() != 28398) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_generate_elc_ephemeral_public_key() != 36799) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_validate_cvc_chain() != 49288) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_verify_cvc_ecdsa_value_signature() != 52414) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_func_verify_ecdsa_value_signature() != 2504) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_method_brainpoolp256r1keypair_private_key() != 7089) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_method_brainpoolp256r1keypair_public_key() != 21212) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_method_cvcchainvalidationresult_end_entity_chr() != 53837) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_method_cvcchainvalidationresult_validated_certificates() != 8444) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_method_cvctrustanchor_reference() != 50798) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_constructor_cvctrustanchor_from_certificate() != 56515) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_openhealth_crypto_checksum_constructor_cvctrustanchor_from_public_key_tlv() != 31750) {
        return InitializationResult.apiChecksumMismatch
    }

    uniffiEnsureOpenhealthAsn1Initialized()
    return InitializationResult.ok
}()

// Make the ensure init function public so that other modules which have external type references to
// our types can call it.
public func uniffiEnsureOpenhealthCryptoInitialized() {
    switch initializationResult {
    case .ok:
        break
    case .contractVersionMismatch:
        fatalError("UniFFI contract version mismatch: try cleaning and rebuilding your project")
    case .apiChecksumMismatch:
        fatalError("UniFFI API checksum mismatch: try cleaning and rebuilding your project")
    }
}

